impl Solution { pub fn max_result(nums: Vec<i32>, k: i32) -> i32 { let (n, mut black_q) = (nums.len(), std::collections::VecDeque::new()); let mut black_dp = vec![0; n]; black_dp[0] = nums[0]; black_q.push_back(0); for i in 1..n { if let Some(&f) = black_q.front() { if f + (k as usize) < i { black_q.pop_front(); } } black_dp[i] = nums[i] + black_dp[*black_q.front().unwrap()]; while let Some(&b) = black_q.back() { if black_dp[b] <= black_dp[i] { black_q.pop_back(); } else { break; } } black_q.push_back(i); } black_dp[n - 1] } }